function DbUtil:getPlayerData(player)
    local subKeys = {}
    for key = DbUtil.FIRST_DATA_KEY, DbUtil.LAST_DATA_KEY do
        table.insert(subKeys, key)
    end
    DBManager:getPlayerManyData(player.userId, subKeys, function(userId, result)
        player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        for subKey, data in pairs(result) do
            player:initDataFromDB(data, subKey)
        end
        player.taskController:init()
        RewardUtil:tryConsumeRewards(player)
        GameGuide:sendDataToClient(player)
    end)

end

